-- =====================================================
-- VERIFICATION
-- =====================================================
SELECT 'Sample data inserted successfully!' AS status;

-- Count records by school
SELECT s.name AS school, 
       (SELECT COUNT(*) FROM students WHERE school_id = s.id) AS students,
       (SELECT COUNT(*) FROM staff WHERE school_id = s.id) AS staff,
       (SELECT COUNT(*) FROM classes WHERE school_id = s.id) AS classes
FROM schools s;